/* ═══════════════════════════════════════════════════════════════
   ONE STEP — Ferrari-level scroll animation
   • Image: zooms in from "afar" (scale 1.3→1.06) + parallax Y
   • Text: slides from outside, each line staggers separately
   • Bleeding word: counter-parallax (moves opposite direction)
   • Everything reverses perfectly on scroll-up
═══════════════════════════════════════════════════════════════ */
function Step({ step, i }) {
  const [secRef, p] = useElP();
  const even = i % 2 === 1;

  /* ── Entry / exit windows ── */
  const entered = ss(p, 0.12, 0.42);   // 0→1 as step enters
  const exiting = ss(p, 0.62, 0.90);   // 0→1 as step exits
  const progress = entered - exiting;  // 0→1→0 — peaks when centred

  /* ── Image: zoom from far (scale 1.35 → 1.06) + slow parallax ── */
  // As progress goes 0→1: scale shrinks from 1.35 to 1.06 (zooms in)
  // As it exits (progress 1→0): scale grows back (zooms out = retrace)
  const imgScale = 1.06 + (1 - progress) * 0.29;   // 1.35 → 1.06 → 1.35
  const imgY     = (p - 0.5) * -80;                 // slow parallax (-40px to +40px)
  const imgBrightness = 0.45 + progress * 0.25;     // 0.45 → 0.70 → 0.45

  /* ── Bleeding word: counter-parallax (moves up as we scroll down) ── */
  const bleedY = (p - 0.5) * 55;   // moves opposite: -27px to +27px

  /* ── Text column: slides from outside edge ── */
  const textX  = (1 - progress) * (even ? 110 : -110);
  const textOp = Math.max(0, Math.min(1, progress * 1.3));

  /* ── Per-line stagger — each line has its own delayed window ── */
  const tagProg   = ss(progress, 0.00, 0.35);
  const titleProg = ss(progress, 0.10, 0.45);
  const descProg  = ss(progress, 0.20, 0.55);
  const listProg  = ss(progress, 0.30, 0.65);

  const lineY = (v) => (1 - v) * 30;

  return (
    <div className={`hiw-step ${even ? "hiw-step--flip" : ""}`} ref={secRef}>

      {/* ── IMAGE SIDE ── */}
      <div className="hiw-step__img-col">
        {/* Ferrari zoom-from-afar: scale AND parallax Y simultaneously */}
        <img
          src={step.img}
          alt={step.title}
          className="hiw-step__img"
          loading="lazy"
          style={{
            transform: `translateY(${imgY}px) scale(${imgScale})`,
            filter: `brightness(${imgBrightness}) saturate(${0.6 + progress * 0.35})`,
          }}
        />
        <div className="hiw-step__img-ov" />
        <div className="hiw-step__img-num"
          style={{ opacity: progress * 1.5, transform: `translateY(${(1-progress)*-16}px)` }}>
          {step.num}
        </div>

        {/* Bleeding word — counter-scrolls (Ferrari style) */}
        <div className="hiw-step__img-bleed"
          style={{ color: `${step.accent}1a`, transform: `translateY(${bleedY}px)` }}>
          {step.headline}
        </div>

        {/* Code snippet — slides up on hover */}
        <div className="hiw-step__code-ov">
          <pre className="hiw-step__code" style={{ borderColor: `${step.accent}35` }}>
            {step.code}
          </pre>
        </div>
      </div>

      {/* ── TEXT SIDE ── */}
      <div
        className="hiw-step__text-col"
        style={{
          transform: `translateX(${textX}px)`,
          opacity: textOp,
          "--a": step.accent,
        }}
      >
        {/* Ghost headline behind text — its own counter-parallax */}
        <div className="hiw-step__ghost"
          style={{ transform: `translateX(${(p - 0.5) * (even ? 30 : -30)}px)` }}>
          {step.headline}
        </div>

        {/* Each text element animates in with staggered delay */}
        <div style={{ opacity: tagProg, transform: `translateY(${lineY(tagProg)}px)` }}>
          <div className="hiw-step__tag">{step.tag} · {step.num}</div>
        </div>

        <div style={{ opacity: titleProg, transform: `translateY(${lineY(titleProg)}px)` }}>
          <h3 className="hiw-step__title">{step.title}</h3>
        </div>

        <div style={{ opacity: descProg, transform: `translateY(${lineY(descProg)}px)` }}>
          <p className="hiw-step__desc">{step.desc}</p>
        </div>

        <ul className="hiw-step__list"
          style={{ opacity: listProg, transform: `translateY(${lineY(listProg)}px)` }}>
          {step.details.map((d, di) => (
            <li key={d} className="hiw-step__item"
              style={{ opacity: ss(listProg, di * 0.15, di * 0.15 + 0.5) }}>
              <span className="hiw-step__bullet" />
              {d}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

/* ── Flow section ── */
function FlowSection({ go }) {
  const [ref, p] = useElP();
  const nodes = [
    { icon:"📄", label:"Your PDF",   sub:"Any research paper" },
    { arrow:true },
    { icon:"🌐", label:"IPFS",       sub:"SHA-256 → CID" },
    { arrow:true },
    { icon:"⛓",  label:"Blockchain", sub:"CID + Wallet + Timestamp" },
    { arrow:true },
    { icon:"✅", label:"Proof",      sub:"Public · Permanent · Verified" },
  ];
  const titleProg = ss(p, 0.04, 0.24);
  return (
    <section className="hiw-flow" ref={ref}>
      {/* Bleed counter-scrolls */}
      <div className="hiw-flow__bleed"
        style={{ transform: `translate(-50%,-50%) translateY(${(p-0.5)*-55}px)` }}>
        FLOW
      </div>
      <div className="hiw-flow__inner">
        <div style={{ opacity: titleProg, transform: `translateY(${(1-titleProg)*40}px)` }}>
          <div className="eyebrow">The Complete Flow</div>
          <h2 className="hiw-flow__h2">End-to-end in one view.</h2>
        </div>
        <div className="hiw-flow__row">
          {nodes.map((item, i) => {
            const np = sss(p, 0.18 + i * 0.045, 0.44 + i * 0.045);
            return item.arrow ? (
              <div className="hiw-flow__arr" key={i}
                style={{ opacity: np, transform: `translateX(${(1-np)*-12}px)` }}>→</div>
            ) : (
              <div className="hiw-flow__node" key={i}
                style={{ opacity: np, transform: `translateY(${(1-np)*36}px) scale(${0.88 + np*0.12})` }}>
                <div className="hiw-flow__node-icon">{item.icon}</div>
                <div className="hiw-flow__node-label">{item.label}</div>
                <div className="hiw-flow__node-sub">{item.sub}</div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

